// log_line_send: append entry to retail_sales.line_send_log
const body = ($input.first().json && $input.first().json.body) || $input.first().json || {};
const esc = v => (v==null||v==='')?'NULL':"'"+String(v).replace(/'/g,"''")+"'";
const saleNo = String(body.sale_no || '').trim();
if (!saleNo) return [{ json: { query: "SELECT 'missing sale_no' AS message" } }];
const type = String(body.type || '').trim();
const status = String(body.status || '').trim();
if (!type || !status) return [{ json: { query: "SELECT 'missing type or status' AS message" } }];
const by = String(body.by || '').trim();
const error = String(body.error || '').trim();
const query = `UPDATE retail_sales SET line_send_log = COALESCE(line_send_log, '[]'::jsonb) || jsonb_build_array(jsonb_build_object('type', ${esc(type)}, 'status', ${esc(status)}, 'at', NOW()::text, 'by', ${esc(by)}, 'error', ${esc(error)})), updated_at = NOW() WHERE sale_no = ${esc(saleNo)} RETURNING sale_no, line_send_log;`;
return [{ json: { query } }];
